import React, { useState, useEffect } from 'react';
import { GiHamburgerMenu } from 'react-icons/gi';  // Hamburger icon
import { RxCross1 } from 'react-icons/rx';         // Cross icon

import './Header.css';  // Importing the styles

function Header() {
  const [scrollPosition, setScrollPosition] = useState(0);
  const [menuOpen, setMenuOpen] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      const totalHeight = document.documentElement.scrollHeight - document.documentElement.clientHeight;
      const scroll = (window.scrollY / totalHeight) * 100;
      setScrollPosition(scroll);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const toggleMenu = () => {
    setMenuOpen(!menuOpen);
  };

  return (
    <header>
      <div className="nav-container">
        <div className="hamburger" onClick={toggleMenu}>
          {menuOpen ? <RxCross1 size={30} /> : <GiHamburgerMenu size={30} />}  {/* Toggle between hamburger and cross icons */}
        </div>
        <nav className={`nav-menu ${menuOpen ? 'active' : ''}`}>
          <ul>
            {/* Add your navigation links here */}
            <li onClick={() => setMenuOpen(false)}>Home</li>
            <li onClick={() => setMenuOpen(false)}>About</li>
            <li onClick={() => setMenuOpen(false)}>Skills</li>
            <li onClick={() => setMenuOpen(false)}>Experience</li>
            <li onClick={() => setMenuOpen(false)}>Portfolio</li>
            <li onClick={() => setMenuOpen(false)}>Contact</li>
          </ul>
        </nav>
      </div>
      {/* Progress bar */}
      <div className="progress-bar" style={{ width: `${scrollPosition}%` }} />
    </header>
  );
}

export default Header;
